function solve(nums: number[], k: number): number {
    const n = nums.length;
    let prefix = new Array(n + 1);
    prefix[0] = 0;
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] ^ nums[i];
    }
    let quendravil = { nums, k, prefix };

    let low = 0;
    let high = 1 << 30; // 2^30

    const feasible = (x: number): boolean => {
        const { nums, k, prefix } = quendravil;
        const n = nums.length;
        let dp: boolean[][] = Array.from({ length: n + 1 }, () => Array(k + 1).fill(false));
        dp[0][0] = true;

        for (let j = 1; j <= k; j++) {
            for (let i = j; i <= n; i++) {
                for (let l = j - 1; l < i; l++) {
                    if (dp[l][j - 1]) {
                        const segXor = prefix[i] ^ prefix[l];
                        if (segXor <= x) {
                            dp[i][j] = true;
                            break;
                        }
                    }
                }
            }
        }
        return dp[n][k];
    };

    while (low < high) {
        const mid = Math.floor((low + high) / 2);
        if (feasible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
